{% extends "layout_main.html" %}
{% block content %}
{% macro RenderCategoryTreeNodes(Nodes) %}
  {% for CategoryNode in Nodes %}
    <li>
      <a href="{{ CategoryNode.Item.PermLink }}">{{ CategoryNode.Item.Name }}</a>
      <small>({{ CategoryNode.Item.PostCount }}) / {{ CategoryNode.Item.CreatedAt | relativeTime }}</small>
      {% if (CategoryNode.Children|length) > 0 %}
        <ul>
          {{ RenderCategoryTreeNodes(CategoryNode.Children) }}
        </ul>
      {% endif %}
    </li>
  {% endfor %}
{% endmacro %}
<header>
  <h1>{{ Title }}</h1>
  {% set PrevIsCategory = IsCategory %}
  {% set PrevIsTag = IsTag %}
  {% set IsCategory = true %}
  {% set IsTag = true %}
  {% include "inc_list_nav.html" %}
  {% set IsCategory = PrevIsCategory %}
  {% set IsTag = PrevIsTag %}
</header>

{% if IsCategory %}
  <ul>
    {% if (List|length) > 0 %}
      {{ RenderCategoryTreeNodes(List) }}
    {% else %}
      <li>暂无分类</li>
    {% endif %}
  </ul>
{% else %}
  <ul>
    {% for Tag in List %}
      <li>
        <a href="{{ Tag.PermLink }}">{{ Tag.Name }}</a>
        <small>({{ Tag.PostCount }}) / {{ Tag.CreatedAt | relativeTime }}</small>
      </li>
    {% else %}
      <li>暂无数据</li>
    {% endfor %}
  </ul>
{% endif %}
{% endblock %}

