{% extends "layout_main.html" %}
{% block content %}
{% from "macro_content.html" import CategoryItem, TagList %}
<header>
  <h1>{{ Entity.Name }}</h1>
  {% include "inc_list_nav.html" %}
</header>

{% if Entity.Description %}
  <section>
    <p>{{ Entity.Description }}</p>
  </section>
{% endif %}

<section>
  <ul>
    {% for Item in List %}
      <li>
        <a href="{{ Item.PermLink }}">{{ Item.Title }}</a><br>
        {% if (not IsCategory) and Item.Category %}
          <small>{{ CategoryItem(Item.Category, true) }}</small><br>
        {% endif %}
        {% if Item.Tags %}
          <small>{{ TagList(Item.Tags, true) }}</small><br>
        {% endif %}
        <small>{{ Item.CreatedAt | relativeTime }}</small>
      </li>
    {% else %}
      <li>暂无文章</li>
    {% endfor %}
  </ul>
</section>
{% endblock %}

files.macro_content.html:
{% macro CategoryItem(Item, Label=false, Sep="") -%}
  {% if Item %}
    <span>{% if Label %}分类{% endif %}{{ Sep }} <a href="{{ Item.PermLink }}">{{ Item.Name }}</a></span>
  {% endif %}
{%- endmacro %}

{% macro TagList(Items, Label=false, Sep="") -%}
  {% if Items and (Items|length) > 0 %}
    <span>
      {% if Label %}标签{% endif %}{{ Sep }}
      {% set TagSep = joiner(", ") %}
      {% for Item in Items %}{{ TagSep() }}<a href="{{ Item.PermLink }}">{{ Item.Name }}</a>{% endfor %}
    </span>
  {% endif %}
{%- endmacro %}

{% macro LoginLink(Label="", URL="") -%}
  {% if IsLogin %}<a href="{{ URL }}">{{ Label }}</a>{% endif %}
{%- endmacro %}

